1	------------------------------------------------------------------------------
2	--  Copyright (c) 2018 by Paul Scherrer Institute, Switzerland
3	--  All rights reserved.
4	--  Authors: Oliver Bruendler
5	------------------------------------------------------------------------------
6	library ieee;
7	use ieee.std_logic_1164.all;
8	use ieee.numeric_std.all;
9	use ieee.math_real.all;
10	
11	use work.psi_common_array_pkg.all;
12	use work.psi_common_math_pkg.all;
13	use work.psi_fix_pkg.all;
14	-- @formatter : off
15	entity psi_fix_cic_dec_fix_nch_par_tdm is
16	  generic(
17	    channels_g       : integer              := 3; -- Min. 2
18	    order_g          : integer              := 4; -- CIC Filter Order
19	    ratio_g          : integer              := 10; -- Decimation ratio watch out the number of channels
20	    diff_delay_g     : natural range 1 to 2 := 1; -- diffrential delay
21	    in_fmt_g         : psi_fix_fmt_t        := (1, 0, 15); -- input format FP
22	    out_fmt_g        : psi_fix_fmt_t        := (1, 0, 15); -- output fromat FP
23	    rst_pol_g        : std_logic            := '1';       -- reset polarity active high = '1'
24	    auto_gain_corr_g : boolean              := True -- Uses up to 25 bits of the datapath and 17 bit correction parameter
25	  );
26	  port(
27	    clk_i  : in  std_logic;             --clk system
28	    rst_i  : in  std_logic;             --rst system
29	    dat_i  : in  std_logic_vector(psi_fix_size(in_fmt_g) * channels_g - 1 downto 0); -- data input
30	    vld_i  : in  std_logic;             -- valid input frequency sampling
31	    dat_o  : out std_logic_vector(psi_fix_size(out_fmt_g) - 1 downto 0); -- data output
32	    vld_o  : out std_logic;             -- valid output new frequency sampling Fs/Ratio
33	    busy_o : out std_logic              -- active high
34	  );
35	end entity;
36	-- @formatter : on
37	architecture rtl of psi_fix_cic_dec_fix_nch_par_tdm is
38	  -- Constants
39	  constant CicGain_c    : real                                                     := (real(ratio_g) * real(diff_delay_g))**real(order_g);
40	  constant CicAddBits_c : integer                                                  := log2ceil(CicGain_c - 0.1); -- WORKAROUND: Vivado does real calculations imprecisely. With the -0.1, wrong results are avoided.
41	  constant Shift_c      : integer                                                  := CicAddBits_c;
42	  constant AccuFmt_c    : psi_fix_fmt_t                                            := (in_fmt_g.S, in_fmt_g.I + CicAddBits_c, in_fmt_g.F);
43	  constant DiffFmt_c    : psi_fix_fmt_t                                            := (out_fmt_g.S, in_fmt_g.I, out_fmt_g.F + order_g + 1);
44	  constant GcInFmt_c    : psi_fix_fmt_t                                            := (1, out_fmt_g.I, work.psi_common_math_pkg.min(24 - out_fmt_g.I, DiffFmt_c.F));
45	  constant GcCoefFmt_c  : psi_fix_fmt_t                                            := (0, 1, 16);
46	  constant GcMultFmt_c  : psi_fix_fmt_t                                            := (1, GcInFmt_c.I + GcCoefFmt_c.I, GcInFmt_c.F + GcCoefFmt_c.F);
47	  constant Gc_c         : std_logic_vector(psi_fix_size(GcCoefFmt_c) - 1 downto 0) := psi_fix_from_real(2.0**real(CicAddBits_c) / CicGain_c, GcCoefFmt_c);
48	
49	  -- Types
50	  type AccuStage_t is array (natural range <>) of std_logic_vector(psi_fix_size(AccuFmt_c) - 1 downto 0);
51	  type Accus_t is array (natural range <>) of AccuStage_t(0 to channels_g - 1);
52	  type Diff_t is array (natural range <>) of std_logic_vector(psi_fix_size(DiffFmt_c) - 1 downto 0);
53	  type InputStage_t is array (natural range <>) of std_logic_vector(psi_fix_size(in_fmt_g) - 1 downto 0);
54	
55	  -- Two Process Method
56	  type two_process_r is record
57	    -- Accu Section
58	    Input_0     : InputStage_t(channels_g - 1 downto 0);
59	    VldAccu     : std_logic_vector(0 to order_g);
60	    Accu        : Accus_t(1 to order_g);
61	    Rcnt        : integer range 0 to ratio_g - 1;
62	    -- Diff Section
63	    VldParTdm   : std_logic;
64	    VldDiff     : std_logic_vector(1 to order_g);
65	    DiffVal     : Diff_t(1 to order_g);
66	    -- GC Stages
67	    GcVld       : std_logic_vector(0 to 2);
68	    GcIn_0      : std_logic_vector(psi_fix_size(GcInFmt_c) - 1 downto 0);
69	    GcMult_1    : std_logic_vector(psi_fix_size(GcMultFmt_c) - 1 downto 0);
70	    GcOut_2     : std_logic_vector(psi_fix_size(out_fmt_g) - 1 downto 0);
71	    -- Output
72	    Outp        : std_logic_vector(psi_fix_size(out_fmt_g) - 1 downto 0);
73	    OutVld      : std_logic;
74	    -- Status
75	    CalcOngoing : std_logic;
76	  end record;
77	  signal r, r_next : two_process_r;
78	
79	  -- Component Connection Signals
80	  signal ParTdmIn  : std_logic_vector(psi_fix_size(DiffFmt_c) * channels_g - 1 downto 0);
81	  signal DiffIn_0  : std_logic_vector(psi_fix_size(DiffFmt_c) - 1 downto 0);
82	  signal VldDiff_0 : std_logic;
83	  signal DiffDel   : Diff_t(0 to order_g - 1);
84	
85	begin
86	  --------------------------------------------------------------------------
87	  -- Combinatorial Process
88	  --------------------------------------------------------------------------
89	  p_comb : process(r, dat_i, vld_i, DiffIn_0, VldDiff_0, DiffDel)
90	    variable v : two_process_r;
91	  begin
92	    -- hold variables stable
93	    v := r;
94	
95	    -- *** Pipe Handling ***
96	    v.VldAccu(v.VldAccu'low + 1 to v.VldAccu'high) := r.VldAccu(r.VldAccu'low to r.VldAccu'high - 1);
97	    v.VldDiff(v.VldDiff'low + 1 to v.VldDiff'high) := r.VldDiff(r.VldDiff'low to r.VldDiff'high - 1);
98	    v.GcVld(v.GcVld'low + 1 to v.GcVld'high)       := r.GcVld(r.GcVld'low to r.GcVld'high - 1);
99	
100	    -- *** Stage Accu 0 ***
101	    -- Input Registers
102	    v.VldAccu(0) := vld_i;
103	    for ch in 0 to channels_g - 1 loop
104	      v.Input_0(ch) := dat_i(psi_fix_size(in_fmt_g) * (ch + 1) - 1 downto psi_fix_size(in_fmt_g) * ch);
105	    end loop;
106	
107	    -- *** Stage Accu 1 ***
108	    -- First accumulator
109	    if r.VldAccu(0) = '1' then
110	      for ch in 0 to channels_g - 1 loop
111	        v.Accu(1)(ch) := psi_fix_add(r.Accu(1)(ch), AccuFmt_c,
112	                                     r.Input_0(ch), in_fmt_g,
113	                                     AccuFmt_c);
114	      end loop;
115	    end if;
116	
117	    -- *** Accumuator Stages (2 to Order) ***
118	    for stage in 1 to order_g - 1 loop
119	      if r.VldAccu(stage) = '1' then
120	        for ch in 0 to channels_g - 1 loop
121	          v.Accu(stage + 1)(ch) := psi_fix_add(r.Accu(stage + 1)(ch), AccuFmt_c,
122	                                               r.Accu(stage)(ch), AccuFmt_c,
123	                                               AccuFmt_c);
124	        end loop;
125	      end if;
126	    end loop;
127	
128	    -- *** Downsampling ***
129	    -- Decimate
130	    v.VldParTdm := '0';
131	    if r.VldAccu(order_g - 1) = '1' then
132	      if r.Rcnt = 0 then
133	        v.VldParTdm := '1';
134	        v.Rcnt      := ratio_g - 1;
135	      else
136	        v.Rcnt := r.Rcnt - 1;
137	      end if;
138	    end if;
139	
140	    -- *** Stage Diff 1 ***
141	    v.VldDiff(1) := VldDiff_0;
142	    -- First differentiator
143	    if VldDiff_0 = '1' then
144	      -- Differentiate
145	      v.DiffVal(1) := psi_fix_sub(DiffIn_0, DiffFmt_c,
146	                                  DiffDel(0), DiffFmt_c,
147	                                  DiffFmt_c);
148	    end if;
149	
150	    -- *** Diff Stages ***
151	    -- Differentiators
152	    for stage in 1 to order_g - 1 loop
153	      if r.VldDiff(stage) = '1' then
154	        -- Differentiate
155	        v.DiffVal(stage + 1) := psi_fix_sub(r.DiffVal(stage), DiffFmt_c,
156	                                            DiffDel(stage), DiffFmt_c,
157	                                            DiffFmt_c);
158	      end if;
159	    end loop;
160	
161	    if auto_gain_corr_g then
162	      -- *** Gain Correction Stage 0 ***
163	      v.GcVld(0) := r.VldDiff(order_g);
164	      v.GcIn_0   := psi_fix_resize(r.DiffVal(order_g), DiffFmt_c, GcInFmt_c, psi_fix_round, psi_fix_sat);
165	
166	      -- *** Gain Correction Stage 1 ***
167	      v.GcMult_1 := psi_fix_mult(r.GcIn_0, GcInFmt_c,
168	                                 Gc_c, GcCoefFmt_c,
169	                                 GcMultFmt_c, psi_fix_trunc, psi_fix_wrap); -- Round/Truncation in next stage
170	      v.GcOut_2  := psi_fix_resize(r.GcMult_1, GcMultFmt_c, out_fmt_g, psi_fix_round, psi_fix_sat);
171	    end if;
172	
173	    -- *** Status Output ***
174	    if (unsigned(r.VldAccu) /= 0) or (VldDiff_0 = '1') or (unsigned(r.VldDiff) /= 0) or (unsigned(r.GcVld) /= 0) then -- OutVld omitted because of 1 cycle PL delay
175	      v.CalcOngoing := '1';
176	    else
177	      v.CalcOngoing := '0';
178	    end if;
179	
180	    -- *** Output Assignment ***
181	    if auto_gain_corr_g then
182	      v.Outp   := r.GcOut_2;
183	      v.OutVld := r.GcVld(2);
184	    else
185	      v.Outp   := psi_fix_resize(r.DiffVal(order_g), DiffFmt_c, out_fmt_g, psi_fix_round, psi_fix_sat);
186	      v.OutVld := r.VldDiff(order_g);
187	    end if;
188	    busy_o <= r.CalcOngoing or r.VldAccu(0);
189	
190	    -- Apply to record
191	    r_next <= v;
192	
193	  end process;
194	
195	  --------------------------------------------------------------------------
196	  -- Output Assignment
197	  --------------------------------------------------------------------------
198	  vld_o <= r.OutVld;
199	  dat_o <= r.Outp;
200	
201	  --------------------------------------------------------------------------
202	  -- Sequential Process
203	  --------------------------------------------------------------------------
204	  p_seq : process(clk_i)
205	  begin
206	    if rising_edge(clk_i) then
207	      assert channels_g >= 2 report "###ERROR###: psi_fix_cic_dec_fix_nch_tdm_tdm: channels_g must be >= 2" severity error;
208	      r <= r_next;
209	      if rst_i = rst_pol_g then
210	        r.VldAccu     <= (others => '0');
211	        r.Accu        <= (others => (others => (others => '0')));
212	        r.Rcnt        <= 0;
213	        r.VldDiff     <= (others => '0');
214	        r.GcVld       <= (others => '0');
215	        r.OutVld      <= '0';
216	        r.VldParTdm   <= '0';
217	        r.CalcOngoing <= '0';
218	      end if;
219	    end if;
220	  end process;
221	
222	  --------------------------------------------------------------------------
223	  -- Component Instantiations
224	  --------------------------------------------------------------------------
225	  -- *** Parallel to TDM conversion before diff-stages ***
226	  g_partdmin : for ch in 0 to channels_g - 1 generate
227	    ParTdmIn(psi_fix_size(DiffFmt_c) * (ch + 1) - 1 downto psi_fix_size(DiffFmt_c) * ch) <= psi_fix_shift_right(r.Accu(order_g)(ch), AccuFmt_c, Shift_c, Shift_c, DiffFmt_c, psi_fix_trunc, psi_fix_wrap);
228	  end generate;
229	
230	  i_partdm : entity work.psi_common_par_tdm
231	    generic map(
232	      ch_nb_g    => channels_g,
233	      ch_width_g => psi_fix_size(DiffFmt_c),
234	      rst_pol_g  => rst_pol_g
235	    )
236	    port map(
237	      clk_i => clk_i,
238	      rst_i => rst_i,
239	      dat_i => ParTdmIn,
240	      vld_i => r.VldParTdm,
241	      dat_o => DiffIn_0,
242	      vld_o => VldDiff_0
243	    );
244	
245	  -- *** Diff-delays ***
246	  g_diffdel : for stage in 0 to order_g - 1 generate
247	    signal DiffDelIn : std_logic_vector(psi_fix_size(DiffFmt_c) - 1 downto 0);
248	    signal DiffVldIn : std_logic;
249	  begin
250	    DiffDelIn <= DiffIn_0 when stage = 0 else r.DiffVal(max(stage, 1));
251	    DiffVldIn <= VldDiff_0 when stage = 0 else r.VldDiff(max(stage, 1));
252	
253	    i_del : entity work.psi_common_delay
254	      generic map(
255	        rst_pol_g   => rst_pol_g,
256	        width_g     => psi_fix_size(DiffFmt_c),
257	        delay_g     => channels_g * diff_delay_g,
258	        rst_state_g => true
259	      )
260	      port map(
261	        clk_i => clk_i,
262	        rst_i => rst_i,
263	        -- Data
264	        dat_i => DiffDelIn,
265	        vld_i => DiffVldIn,
266	        dat_o => DiffDel(stage)
267	      );
268	  end generate;
269	
270	end architecture;
271

