27	    max_ratio_g      : natural              := 12;                              -- maximum ratio decimation allowed as it is settable
28	    diff_delay_g     : natural range 1 to 2 := 1;                               -- differential delay
29	    in_fmt_g         : psi_fix_fmt_t          := (1, 0, 15);                    -- input data format FP
30	    out_fmt_g        : psi_fix_fmt_t          := (1, 0, 15);                    -- output data format FP
