32	    auto_gain_corr_g : boolean              := True                             -- Use CfgGainCorr for fine-grained gain correction (beyond pure shifting)
33	  );
34	  port(
35	    -- Control Signals
36	    clk_i           : in  std_logic;                                             -- clk system
37	    rst_i           : in  std_logic;                                             -- rst system
38	    -- Configuration (only change when in reset!)
39	    cfg_ratio_i     : in  std_logic_vector(log2ceil(max_ratio_g) - 1 downto 0);  -- Ratio-1 (0 --> no decimation, 3 --> decimation by 4)
40	    cfg_shift_i     : in  std_logic_vector(7 downto 0);                          -- Shifting by more than 255 bits is not supported, this would lead to timing issues anyways
41	    cfg_gain_corr_i : in  std_logic_vector(16 downto 0);                         -- Gain correction factor in format [0,1,16]
42	    -- Data Ports
43	    dat_i           : in  std_logic_vector(psi_fix_size(in_fmt_g) - 1 downto 0); -- data input
44	    vld_i           : in  std_logic;                                             -- valid input frequency samping
45	    dat_o           : out std_logic_vector(psi_fix_size(out_fmt_g) - 1 downto 0);-- data output
46	    vld_o           : out std_logic;                                             -- valid output new frequency sampling Fs/Ratio
47	    -- Status Output
48	    busy_o          : out std_logic                                              -- active high
49	  );
50	end entity;
