52	architecture rtl of psi_fix_cic_dec_cfg_nch_tdm_tdm is
53	  -- Constants
54	  constant MaxCicGain_c    : real        := (real(max_ratio_g) * real(diff_delay_g))**real(order_g);
55	  constant MaxCicAddBits_c : integer     := log2ceil(MaxCicGain_c - 0.1); -- WORKAROUND: Vivado does real calculations imprecisely. With the -0.1, wrong results are avoided.
56	  constant MaxShift_c      : integer     := MaxCicAddBits_c;
57	  constant AccuFmt_c       : psi_fix_fmt_t := (in_fmt_g.S, in_fmt_g.I + MaxCicAddBits_c, in_fmt_g.F);
58	  constant DiffFmt_c       : psi_fix_fmt_t := (out_fmt_g.S, in_fmt_g.I, out_fmt_g.F + order_g + 1);
59	  constant GcInFmt_c       : psi_fix_fmt_t := (1, out_fmt_g.I, work.psi_common_math_pkg.min(24 - out_fmt_g.I, DiffFmt_c.F));
60	  constant GcCoefFmt_c     : psi_fix_fmt_t := (0, 1, 16);
61	  constant GcMultFmt_c     : psi_fix_fmt_t := (1, GcInFmt_c.I + GcCoefFmt_c.I, GcInFmt_c.F + GcCoefFmt_c.F);
62	  constant SftFmt_c        : psi_fix_fmt_t := (AccuFmt_c.S, AccuFmt_c.I, max(AccuFmt_c.F, DiffFmt_c.F));
63	
64	  -- Types
65	  type Accus_t is array (natural range <>) of std_logic_vector(psi_fix_size(AccuFmt_c) - 1 downto 0);
66	  type Diff_t is array (natural range <>) of std_logic_vector(psi_fix_size(DiffFmt_c) - 1 downto 0);
67	
68	  -- Two Process Method
69	  type two_process_r is record
70	    -- GainCorr Registers
71	    GcCoef      : std_logic_vector(psi_fix_size(GcCoefFmt_c) - 1 downto 0);
72	    -- Accu Section
73	    Input_0     : std_logic_vector(psi_fix_size(in_fmt_g) - 1 downto 0);
74	    VldAccu     : std_logic_vector(0 to order_g);
75	    Accu        : Accus_t(1 to order_g);
76	    Rcnt        : integer range 0 to max_ratio_g - 1;
77	    Chcnt       : integer range 0 to channels_g - 1;
78	    SftVldCnt   : unsigned(4 downto 0); -- Maximum shift is 255
79	    -- Diff Section
80	    DiffIn_0    : std_logic_vector(psi_fix_size(DiffFmt_c) - 1 downto 0);
81	    VldDiff     : std_logic_vector(0 to order_g);
82	    DiffVal     : Diff_t(1 to order_g);
83	    -- GC Stages
84	    GcVld       : std_logic_vector(0 to 2);
85	    GcIn_0      : std_logic_vector(psi_fix_size(GcInFmt_c) - 1 downto 0);
86	    GcMult_1    : std_logic_vector(psi_fix_size(GcMultFmt_c) - 1 downto 0);
87	    GcOut_2     : std_logic_vector(psi_fix_size(out_fmt_g) - 1 downto 0);
88	    -- Output
89	    Outp        : std_logic_vector(psi_fix_size(out_fmt_g) - 1 downto 0);
90	    OutVld      : std_logic;
91	    -- Status
92	    CalcOngoing : std_logic;
93	  end record;
94	  signal r, r_next : two_process_r;
95	
96	  -- Component Connection Signals
97	  signal DiffDel : Diff_t(0 to order_g - 1);
98	  signal IntDel  : Accus_t(1 to order_g);
99	
100	  signal ShiftSel     : std_logic_vector(log2ceil(MaxShift_c + 1) - 1 downto 0);
101	  signal ShiftVld     : std_logic;
102	  signal ShiftDataIn  : std_logic_vector(psi_fix_size(SftFmt_c) - 1 downto 0);
103	  signal ShiftDataOut : std_logic_vector(psi_fix_size(SftFmt_c) - 1 downto 0);
104	
105	begin
106	  --------------------------------------------------------------------------
107	  -- Combinatorial Process
108	  --------------------------------------------------------------------------
109	  p_comb : process(r, dat_i, vld_i, DiffDel, IntDel, ShiftDataOut, ShiftVld, cfg_gain_corr_i, cfg_ratio_i)
110	    variable v : two_process_r;
111	  begin
112	    -- hold variables stable
113	    v := r;
114	
115	    -- *** Pipe Handling ***
116	    v.VldAccu(v.VldAccu'low + 1 to v.VldAccu'high) := r.VldAccu(r.VldAccu'low to r.VldAccu'high - 1);
117	    v.VldDiff(v.VldDiff'low + 1 to v.VldDiff'high) := r.VldDiff(r.VldDiff'low to r.VldDiff'high - 1);
118	    v.GcVld(v.GcVld'low + 1 to v.GcVld'high)       := r.GcVld(r.GcVld'low to r.GcVld'high - 1);
119	
120	    -- *** Stage Accu 0 ***
121	    -- Input Registers
122	    v.VldAccu(0) := vld_i;
123	    v.Input_0    := dat_i;
124	
125	    -- *** Stage Accu 1 ***
126	    -- First accumulator
127	    if r.VldAccu(0) = '1' then
128	      v.Accu(1) := psi_fix_add(IntDel(1), AccuFmt_c,
129	                             r.Input_0, in_fmt_g,
130	                             AccuFmt_c);
131	    end if;
132	
133	    -- *** Accumuator Stages (2 to Order) ***
134	    for stage in 1 to order_g - 1 loop
135	      if r.VldAccu(stage) = '1' then
136	        v.Accu(stage + 1) := psi_fix_add(IntDel(stage + 1), AccuFmt_c,
137	                                       r.Accu(stage), AccuFmt_c,
138	                                       AccuFmt_c);
139	      end if;
140	    end loop;
141	
142	    -- *** Shift ***
143	    -- Shifter implemented as separate component, see below
144	    if r.VldAccu(order_g) = '1' then
145	      v.SftVldCnt := r.SftVldCnt + 1;
146	    end if;
147	    if ShiftVld = '1' then
148	      v.SftVldCnt := v.SftVldCnt - 1;
149	    end if;
150	
151	    -- *** Stage Diff 0 ***
152	    -- Decimate
153	    v.VldDiff(0) := '0';
154	    if ShiftVld = '1' then
155	      -- channel counter
156	      if r.Chcnt = 0 then
157	        v.Chcnt := channels_g - 1;
158	        if r.Rcnt = 0 then
159	          v.Rcnt := to_integer(unsigned(cfg_ratio_i));
160	        else
161	          v.Rcnt := r.Rcnt - 1;
162	        end if;
163	      else
164	        v.Chcnt := r.Chcnt - 1;
165	      end if;
166	      -- ratio counter
167	      if r.Rcnt = 0 then
168	        v.VldDiff(0) := '1';
169	        v.DiffIn_0   := psi_fix_resize(ShiftDataOut, SftFmt_c, DiffFmt_c, psi_fix_trunc, psi_fix_wrap);
170	      end if;
171	    end if;
172	
173	    -- *** Stage Diff 1 ***
174	    -- First differentiator
175	    if r.VldDiff(0) = '1' then
176	      -- Differentiate
177	      v.DiffVal(1) := psi_fix_sub(r.DiffIn_0, DiffFmt_c,
178	                                DiffDel(0), DiffFmt_c,
179	                                DiffFmt_c);
180	    end if;
181	
182	    -- *** Diff Stages ***
183	    -- Differentiators
184	    for stage in 1 to order_g - 1 loop
185	      if r.VldDiff(stage) = '1' then
186	        -- Differentiate
187	        v.DiffVal(stage + 1) := psi_fix_sub(r.DiffVal(stage), DiffFmt_c,
188	                                          DiffDel(stage), DiffFmt_c,
189	                                          DiffFmt_c);
190	      end if;
191	    end loop;
192	
193	    if auto_gain_corr_g then
194	      -- *** Gain Coefficient Register ***
195	      v.GcCoef := cfg_gain_corr_i;
196	
197	      -- *** Gain Correction Stage 0 ***
198	      v.GcVld(0) := r.VldDiff(order_g);
199	      v.GcIn_0   := psi_fix_resize(r.DiffVal(order_g), DiffFmt_c, GcInFmt_c, psi_fix_round, psi_fix_sat);
200	
201	      -- *** Gain Correction Stage 1 ***
202	      v.GcMult_1 := psi_fix_mult(r.GcIn_0, GcInFmt_c,
203	                               cfg_gain_corr_i, GcCoefFmt_c,
204	                               GcMultFmt_c, psi_fix_trunc, psi_fix_wrap); -- Round/Truncation in next stage
205	      v.GcOut_2  := psi_fix_resize(r.GcMult_1, GcMultFmt_c, out_fmt_g, psi_fix_round, psi_fix_sat);
206	    end if;
207	
208	    -- *** Status Output ***
209	    if (unsigned(r.VldAccu) /= 0) or (unsigned(r.VldDiff) /= 0) or (unsigned(r.GcVld) /= 0) or (r.SftVldCnt /= 0) then -- OutVld omitted because of 1 cycle PL delay
210	      v.CalcOngoing := '1';
211	    else
212	      v.CalcOngoing := '0';
213	    end if;
214	
215	    -- *** Output Assignment ***
216	    if auto_gain_corr_g then
217	      v.Outp   := r.GcOut_2;
218	      v.OutVld := r.GcVld(2);
219	    else
220	      v.Outp   := psi_fix_resize(r.DiffVal(order_g), DiffFmt_c, out_fmt_g, psi_fix_round, psi_fix_sat);
221	      v.OutVld := r.VldDiff(order_g);
222	    end if;
223	    busy_o <= r.CalcOngoing or r.VldAccu(0);
224	
225	    -- Apply to record
226	    r_next <= v;
227	
228	  end process;
229	
230	  --------------------------------------------------------------------------
231	  -- Output Assignment
232	  --------------------------------------------------------------------------
233	  vld_o <= r.OutVld;
234	  dat_o <= r.Outp;
235	
236	  --------------------------------------------------------------------------
237	  -- Sequential Process
238	  --------------------------------------------------------------------------
239	  p_seq : process(clk_i)
240	  begin
241	    if rising_edge(clk_i) then
242	      assert channels_g >= 2 report "###ERROR###: psi_fix_cic_dec_cfg_nch_tdm_tdm: channels_g must be >= 2" severity error;
243	      r <= r_next;
244	      if rst_i = rst_pol_g then
245	        r.VldAccu     <= (others => '0');
246	        r.Accu        <= (others => (others => '0'));
247	        r.Rcnt        <= 0;
248	        r.Chcnt       <= channels_g - 1;
249	        r.VldDiff     <= (others => '0');
250	        r.GcVld       <= (others => '0');
251	        r.OutVld      <= '0';
252	        r.CalcOngoing <= '0';
253	        r.SftVldCnt   <= (others => '0');
254	      end if;
255	    end if;
256	  end process;
257	
258	  --------------------------------------------------------------------------
259	  -- Component Instantiations
260	  --------------------------------------------------------------------------
261	  -- *** Dynamic Shifter ***
262	  ShiftSel    <= cfg_shift_i(ShiftSel'range);
263	  ShiftDataIn <= psi_fix_resize(r.Accu(order_g), AccuFmt_c, SftFmt_c);
264	  i_sft : entity work.psi_common_dyn_sft
265	    generic map(
266	      direction_g          => "RIGHT",
267	      sel_bit_per_stage_g => 4,
268	      max_shift_g           => MaxShift_c,
269	      width_g              => psi_fix_size(SftFmt_c),
270	      sign_extend_g         => true
271	    )
272	    port map(
273	      clk_i     => clk_i,
274	      rst_i     => rst_i,
275	      vld_i   => r.VldAccu(order_g),
276	      shift_i => ShiftSel,
277	      dat_i  => ShiftDataIn,
278	      vld_o  => ShiftVld,
279	      dat_o => ShiftDataOut
280	    );
281	
282	  -- *** Diff-delays ***
283	  g_diffdel : for stage in 0 to order_g - 1 generate
284	    signal DiffDelIn : std_logic_vector(psi_fix_size(DiffFmt_c) - 1 downto 0);
285	    signal DiffVldIn : std_logic;
286	  begin
287	    DiffDelIn <= r.DiffIn_0 when stage = 0 else r.DiffVal(max(stage, 1));
288	    DiffVldIn <= r.VldDiff(0) when stage = 0 else r.VldDiff(max(stage, 1));
289	
290	    i_del : entity work.psi_common_delay
291	      generic map(
292	        width_g    => psi_fix_size(DiffFmt_c),
293	        delay_g    => channels_g * diff_delay_g,
294	        rst_state_g => true
295	      )
296	      port map(
297	        clk_i     => clk_i,
298	        rst_i     => rst_i,
299	        -- Data
300	        dat_i  => DiffDelIn,
301	        vld_i   => DiffVldIn,
302	        dat_o => DiffDel(stage)
303	      );
304	  end generate;
305	
306	  -- *** Int-delays ***
307	  g_intdel : for stage in 0 to order_g - 1 generate
308	  begin
309	    i_del : entity work.psi_common_delay
310	      generic map(
311	        width_g    => psi_fix_size(AccuFmt_c),
312	        delay_g    => channels_g - 1,
313	        rst_state_g => true
314	      )
315	      port map(
316	        clk_i     => clk_i,
317	        rst_i     => rst_i,
318	        -- Data
319	        dat_i  => r.Accu(stage + 1),
320	        vld_i   => r.VldAccu(stage),
321	        dat_o => IntDel(stage + 1)
322	      );
323	  end generate;
324	
325	end architecture;
